import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Route, Routes, Navigate } from "react-router-dom";
import axios from "axios";
import Login from "./pages/Login";
import Home from "./pages/HomePage/Home";
import Admin from "./pages/Admin/Admin";
import Register from "./pages/Register";

function App() {
  const [isAdmin, setIsAdmin] = useState(null); // Initializing with null to indicate loading
  const [email, setEmail] = useState(localStorage.getItem("userEmail") || "");

  // Function to check admin status
  const checkAdminStatus = async (email) => {
    try {
      if (!email) return false;

      const response = await axios.get("http://192.168.66.59:5000/api/clients");
      const client = response.data.find((c) => c.email === email);
      return client ? client.is_admin : false;
    } catch (error) {
      console.error("Error checking admin status:", error);
      return false;
    }
  };

  // Run admin check when email exists
  useEffect(() => {
    if (email) {
      checkAdminStatus(email).then(setIsAdmin);
    } else {
      setIsAdmin(false); // If no email, consider the user not an admin
    }
  }, [email]);

  // If isAdmin is null, it means the admin status is still being checked
  if (isAdmin === null) {
    return <div>Загрузка...</div>; // Or you can show a spinner/loading component
  }

  return (
    <Router>
      <Routes>
        <Route path="/register" element={<Register />} />
        <Route path="/login" element={<Login setEmail={setEmail} />} />
        <Route path="/" element={<Login setEmail={setEmail} />} />

        <Route
          path="/home"
          element={
            !email ? <Navigate to="/login" /> : isAdmin ? <Navigate to="/admin" /> : <Home />
          }
        />

        <Route path="/admin" element={isAdmin ? <Admin /> : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
